	fp* d_in2_sub_cumh_sel_all = (fp*)malloc(sizeof(fp) * common.in2_sub_cumh_sel_elem * common.allPoints);
	fp* d_in2_sub2_all = (fp*)malloc(sizeof(fp) * common.in2_sub2_elem * common.allPoints);
	fp* d_in2_sqr_all = (fp*)malloc(sizeof(fp) * common.in2_sqr_elem * common.allPoints);
	fp* d_in2_sqr_sub2_all = (fp*)malloc(sizeof(fp) * common.in2_sqr_sub2_elem * common.allPoints);
	fp* d_in_sqr_all = (fp*)malloc(sizeof(fp) * common.in_sqr_elem * common.allPoints);
	fp* d_tMask_all = (fp*)malloc(sizeof(fp) * common.tMask_elem * common.allPoints);
	fp* d_mask_conv_all = (fp*)malloc(sizeof(fp) * common.mask_conv_elem * common.allPoints);

	fp* d_in_mod_temp_all = (fp*)malloc(sizeof(fp) * common.in_elem * common.allPoints);
	fp* in_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_cols * common.allPoints);
	fp* in_sqr_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_sqr_rows * common.allPoints);
	fp* par_max_val_all = (fp*)malloc(sizeof(fp) * common.mask_conv_rows * common.allPoints);
	int* par_max_coo_all = (int*)malloc(sizeof(int) * common.mask_conv_rows * common.allPoints);

	fp* in_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
	fp* in_sqr_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
	fp* denomT_all = (fp*)malloc(sizeof(fp) * common.allPoints);

	fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);

	printf("# of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
		   common.allPoints, NUMBER_THREADS);

	printf("frame progress: ");
	fflush(NULL);

	for (int frame_no = 0; frame_no < common.frames_processed; frame_no++) {

